    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    groups = defaultdict(list)
    for result in search_results:
        group_key = result.metadata.get(group_by_field, 'unknown')
        groups[group_key].append(result)

    result_dict = {}
    for group_key, group in groups.items():
        stats = {}
        if aggregation_funcs is None:
            # Default aggregations
            count = len(group)
            stats['count'] = count
            if count > 0:
                sum_scores = sum(result.score for result in group)
                stats['average_score'] = sum_scores / count
                stats['max_score'] = max(result.score for result in group)
                stats['min_score'] = min(result.score for result in group)
            else:
                stats['average_score'] = 0.0
                stats['max_score'] = 0.0
                stats['min_score'] = 0.0
        else:
            # Custom aggregations
            for field_name, func in aggregation_funcs.items():
                try:
                    values = []
                    for result in group:
                        try:
                            value = getattr(result, field_name)
                        except AttributeError:
                            value = result.metadata.get(field_name)
                        values.append(value)
                    stats[field_name] = func(values)
                except Exception:
                    # Skip if aggregation fails
                    continue
        result_dict[group_key] = stats

    return result_dict

