    Evaluate metadata filters against a search result.

    Args:
        result: SearchResult object
        filters: Filter specifications to evaluate

    Returns:
        True if all filters pass, False otherwise
    """
    for field_name, filter_spec in filters.items():
        # Check if field exists in metadata
        if field_name not in result.metadata:
            return False

