            elif operator == "!=":
                if field_value == expected_value:
                    return False
            elif operator == "<":
                if not (isinstance(field_value, (int, float)) and field_value < expected_value):
                    return False
            elif operator == "<=":
                if not (isinstance(field_value, (int, float)) and field_value <= expected_value):
                    return False
            elif operator == ">":
                if not (isinstance(field_value, (int, float)) and field_value > expected_value):
                    return False
            elif operator == ">=":
                if not (isinstance(field_value, (int, float)) and field_value >= expected_value):
                    return False
            elif operator == "in":
                if not isinstance(expected_value, (list, tuple, set)):
                    raise ValueError("'in' operator requires a list, tuple, or set")
                if field_value not in expected_value:
                    return False
            elif operator == "not_in":
